from __future__ import annotations

import json
from collections import defaultdict
from collections.abc import Iterable, Mapping
from dataclasses import dataclass
from datetime import date, datetime
from enum import Enum
from pathlib import Path

import anyio


@dataclass(frozen=True, slots=True)
class Citation:
    source_id: str | None = None
    source_kind: str | None = None
    source_uri: str | None = None
    locator: str | None = None
    quote: str | None = None


@dataclass(frozen=True, slots=True)
class RenderRecord:
    section: str
    key: str
    status: str
    value: object
    question: str | None
    fact_id: str | None
    citation: Citation
    confidence: float | None


def building_markdown_path(output_dir: Path, property_id: str) -> Path:
    safe_property_id = _safe_property_id(property_id)
    return output_dir / safe_property_id / "building.md"


def render_building_markdown(property_id: str, records: Iterable[object]) -> str:
    safe_property_id = _safe_property_id(property_id)
    render_records = sorted(
        _iter_render_records(safe_property_id, records),
        key=_record_sort_key,
    )

    lines = [f"# Building {safe_property_id}", ""]
    if not render_records:
        lines.append("_No active or pending facts._")
        lines.append("")
        return "\n".join(lines)

    by_section: dict[str, list[RenderRecord]] = defaultdict(list)
    for record in render_records:
        by_section[record.section].append(record)

    for section in sorted(by_section, key=_sort_text):
        lines.extend((f"## {_section_title(section)}", ""))
        section_records = by_section[section]
        active = [record for record in section_records if record.status == "active"]
        pending_questions = [
            record for record in section_records if record.status == "pending" and record.question
        ]
        pending_facts = [
            record
            for record in section_records
            if record.status == "pending" and not record.question
        ]

        if active:
            lines.extend(("### Active Facts", ""))
            lines.extend(_fact_line(record) for record in active)
            lines.append("")
        if pending_questions:
            lines.extend(("### Pending Questions", ""))
            lines.extend(_question_line(record) for record in pending_questions)
            lines.append("")
        if pending_facts:
            lines.extend(("### Pending Facts", ""))
            lines.extend(_fact_line(record) for record in pending_facts)
            lines.append("")

    return "\n".join(lines)


async def write_building_markdown(
    output_dir: Path,
    property_id: str,
    records: Iterable[object],
) -> Path:
    path = building_markdown_path(output_dir, property_id)
    content = render_building_markdown(property_id, records)
    async_path = anyio.Path(path)
    await async_path.parent.mkdir(parents=True, exist_ok=True)
    await async_path.write_text(content, encoding="utf-8")
    return path


def _iter_render_records(property_id: str, records: Iterable[object]) -> Iterable[RenderRecord]:
    for record in records:
        data = _as_mapping(record)
        if data is None or not _belongs_to_property(property_id, data):
            continue

        section = _text(data.get("section"))
        if section is None:
            continue
        status = _status(data.get("status"))
        if status not in {"active", "pending"}:
            continue

        question = _first_text(data, ("question", "message", "review_hint"))
        value_missing = "value" not in data
        value = None if value_missing else data.get("value")
        key = _text(data.get("key")) or ("question" if question else "fact")
        citation = _citation(data)
        confidence = _confidence(data.get("confidence"))

        yield RenderRecord(
            section=section,
            key=key,
            status=status,
            value=value,
            question=question if status == "pending" and value_missing else None,
            fact_id=_text(data.get("fact_id")),
            citation=citation,
            confidence=confidence,
        )


def _as_mapping(record: object) -> Mapping[str, object] | None:
    if isinstance(record, Mapping):
        return record

    model_dump = getattr(record, "model_dump", None)
    if callable(model_dump):
        try:
            dumped = model_dump(mode="python")
        except TypeError:
            dumped = model_dump()
        return dumped if isinstance(dumped, Mapping) else None

    return None


def _belongs_to_property(property_id: str, data: Mapping[str, object]) -> bool:
    record_property_id = _text(data.get("property_id"))
    return record_property_id is None or record_property_id == property_id


def _status(value: object) -> str:
    text = _text(value)
    return (text or "active").lower()


def _citation(data: Mapping[str, object]) -> Citation:
    nested = _as_mapping(data.get("citation")) or _as_mapping(data.get("source")) or {}
    return Citation(
        source_id=_first_text(nested, ("source_id", "id")) or _first_text(data, ("source_id",)),
        source_kind=_first_text(nested, ("source_kind", "kind"))
        or _first_text(data, ("source_kind",)),
        source_uri=_first_text(nested, ("source_uri", "uri")) or _first_text(data, ("source_uri",)),
        locator=_first_text(nested, ("locator", "source_locator"))
        or _first_text(data, ("source_locator", "locator")),
        quote=_first_text(nested, ("quote", "source_excerpt"))
        or _first_text(data, ("source_excerpt", "quote")),
    )


def _first_text(data: Mapping[str, object], keys: tuple[str, ...]) -> str | None:
    for key in keys:
        text = _text(data.get(key))
        if text:
            return text
    return None


def _text(value: object) -> str | None:
    if value is None:
        return None
    if isinstance(value, Enum):
        value = value.value
    text = str(value).strip()
    return text or None


def _confidence(value: object) -> float | None:
    if value is None:
        return None
    try:
        confidence = float(value)
    except (TypeError, ValueError):
        return None
    if confidence < 0 or confidence > 1:
        return None
    return confidence


def _fact_line(record: RenderRecord) -> str:
    return f"- {_code_span(record.key)}: {_format_value(record.value)}{_citation_suffix(record)}"


def _question_line(record: RenderRecord) -> str:
    question = record.question or _format_value(record.value)
    return f"- {_code_span(record.key)}: {_inline_text(question)}{_citation_suffix(record)}"


def _citation_suffix(record: RenderRecord) -> str:
    parts: list[str] = []
    source = _source_text(record.citation)
    if source is not None:
        parts.append(f"source: {source}")
    if record.citation.locator is not None:
        parts.append(f"locator: {_code_span(record.citation.locator)}")
    if record.confidence is not None:
        parts.append(f"confidence: {_format_confidence(record.confidence)}")
    if not parts:
        return ""

    suffix = f" _({'; '.join(parts)})_"
    if record.citation.quote is None:
        return suffix
    return f"{suffix}\n  > {_inline_text(record.citation.quote)}"


def _source_text(citation: Citation) -> str | None:
    if citation.source_kind is not None and citation.source_id is not None:
        label = f"{citation.source_kind}:{citation.source_id}"
    else:
        label = citation.source_id or citation.source_kind
    if label is None:
        return None
    if citation.source_uri is None:
        return _escape_markdown(label)
    return f"[{_escape_link_label(label)}]({citation.source_uri})"


def _format_value(value: object) -> str:
    if isinstance(value, str):
        return _inline_text(value)
    return json.dumps(
        _json_ready(value),
        default=str,
        ensure_ascii=False,
        separators=(", ", ": "),
        sort_keys=True,
    )


def _json_ready(value: object) -> object:
    if isinstance(value, Enum):
        return value.value
    if isinstance(value, Mapping):
        return {str(key): _json_ready(value[key]) for key in sorted(value, key=str)}
    if isinstance(value, tuple | list):
        return [_json_ready(item) for item in value]
    if isinstance(value, set | frozenset):
        return [_json_ready(item) for item in sorted(value, key=str)]
    if isinstance(value, datetime | date):
        return value.isoformat()
    return value


def _format_confidence(value: float) -> str:
    return f"{value:.3f}".rstrip("0").rstrip(".")


def _inline_text(value: object) -> str:
    return " ".join(str(value).split())


def _code_span(value: object) -> str:
    text = _inline_text(value)
    if "`" not in text:
        return f"`{text}`"
    return f"`` {text} ``"


def _escape_markdown(value: str) -> str:
    return value.replace("\\", "\\\\").replace("*", "\\*").replace("_", "\\_")


def _escape_link_label(value: str) -> str:
    return _escape_markdown(value).replace("[", "\\[").replace("]", "\\]")


def _section_title(section: str) -> str:
    return section.replace("_", " ").replace("-", " ").title()


def _record_sort_key(record: RenderRecord) -> tuple[str, ...]:
    return (
        _sort_text(record.section),
        record.status,
        _sort_text(record.key),
        _sort_text(record.fact_id or ""),
        _sort_text(_format_value(record.value)),
        _sort_text(record.question or ""),
        _sort_text(record.citation.source_kind or ""),
        _sort_text(record.citation.source_id or ""),
        _sort_text(record.citation.locator or ""),
    )


def _sort_text(value: str) -> str:
    return value.casefold()


def _safe_property_id(property_id: str) -> str:
    safe_property_id = property_id.strip()
    parts = Path(safe_property_id).parts
    if (
        not safe_property_id
        or Path(safe_property_id).is_absolute()
        or ".." in parts
        or len(parts) != 1
    ):
        raise ValueError("invalid property_id")
    return safe_property_id

from __future__ import annotations

from fastmcp.exceptions import ToolError
from fastmcp.server.dependencies import get_access_token

from app.mcp.orgs import org_can_access, properties_for_org


def current_org_id() -> str | None:
    token = get_access_token()
    if token is None:
        return None
    claims = getattr(token, "claims", None) or {}
    org_id = claims.get("org_id") or claims.get("organization_id")
    return str(org_id) if org_id else None


def require_org_id() -> str:
    org_id = current_org_id()
    if org_id is None:
        raise ToolError("authenticated token missing org_id claim")
    return org_id


def assert_property_access(property_id: str) -> None:
    org_id = current_org_id()
    if org_id is None:
        raise ToolError("authenticated token missing org_id claim")
    if not org_can_access(org_id, property_id):
        raise ToolError(f"org {org_id!r} has no access to property {property_id!r}")


def allowed_properties() -> frozenset[str]:
    org_id = current_org_id()
    return properties_for_org(org_id)

