from __future__ import annotations

from collections.abc import Iterable, Mapping
from dataclasses import dataclass
from typing import Literal, Protocol, runtime_checkable

from pydantic import BaseModel, ConfigDict, Field, JsonValue

from app.ingest.envelope import Identifier, validate_identifier

AdapterType = Literal["extractor", "llm_tool"]


@runtime_checkable
class Skill(Protocol):
    async def __call__(self, input: BaseModel) -> BaseModel:
        """Run a deterministic skill against a validated Pydantic input model."""


class SkillContract(BaseModel):
    model_config = ConfigDict(extra="forbid", frozen=True)

    name: Identifier
    adapter_type: AdapterType
    input_schema: dict[str, JsonValue] = Field(default_factory=dict)
    output_schema: dict[str, JsonValue] = Field(default_factory=dict)


@dataclass(frozen=True)
class SkillRegistration:
    name: str
    skill: Skill
    adapter_type: AdapterType
    input_model: type[BaseModel]
    output_model: type[BaseModel]

    def __post_init__(self) -> None:
        object.__setattr__(self, "name", validate_identifier(self.name.strip()))
        if not callable(self.skill):
            msg = "skill must be callable"
            raise TypeError(msg)
        if not issubclass(self.input_model, BaseModel):
            msg = "input_model must inherit from BaseModel"
            raise TypeError(msg)
        if not issubclass(self.output_model, BaseModel):
            msg = "output_model must inherit from BaseModel"
            raise TypeError(msg)

    def contract(self) -> SkillContract:
        return SkillContract(
            name=self.name,
            adapter_type=self.adapter_type,
            input_schema=self.input_model.model_json_schema(),
            output_schema=self.output_model.model_json_schema(),
        )


class SkillRegistry:
    def __init__(self, registrations: Iterable[SkillRegistration] = ()) -> None:
        self._registrations: dict[str, SkillRegistration] = {}
        for registration in registrations:
            self.add(registration)

    def add(self, registration: SkillRegistration) -> SkillRegistration:
        if registration.name in self._registrations:
            msg = f"skill already registered: {registration.name}"
            raise ValueError(msg)
        self._registrations[registration.name] = registration
        return registration

    def register(
        self,
        *,
        name: str,
        skill: Skill,
        adapter_type: AdapterType,
        input_model: type[BaseModel],
        output_model: type[BaseModel],
    ) -> SkillRegistration:
        return self.add(
            SkillRegistration(
                name=name,
                skill=skill,
                adapter_type=adapter_type,
                input_model=input_model,
                output_model=output_model,
            )
        )

    def get(self, name: str) -> SkillRegistration:
        skill_name = validate_identifier(name.strip())
        try:
            return self._registrations[skill_name]
        except KeyError:
            msg = f"unknown skill: {skill_name}"
            raise KeyError(msg) from None

    def contract(self, name: str) -> SkillContract:
        return self.get(name).contract()

    def contracts(self) -> list[SkillContract]:
        return [registration.contract() for registration in self._registrations.values()]

    async def dispatch(self, name: str, input: BaseModel | Mapping[str, object]) -> BaseModel:
        registration = self.get(name)
        if isinstance(input, BaseModel):
            skill_input = registration.input_model.model_validate(input.model_dump())
        else:
            skill_input = registration.input_model.model_validate(input)
        output = await registration.skill(skill_input)
        return registration.output_model.model_validate(output)

from __future__ import annotations

from collections.abc import Collection, Mapping, Sequence
from dataclasses import dataclass, field
from typing import Protocol, runtime_checkable

from pydantic import BaseModel

from app.extract.models import Extractor, Payload
from app.ingest.envelope import Envelope, validate_identifier
from app.skills.base import SkillRegistry


@runtime_checkable
class Classifier(Protocol):
    async def classify(self, envelope: Envelope, payload: Payload) -> str:
        """Classify one envelope before extractor routing."""


@runtime_checkable
class Observer(Protocol):
    async def observe(self, event: str, payload: BaseModel) -> None:
        """Observe engine events without owning core control flow."""


@dataclass(frozen=True)
class VerticalPlugin:
    name: str
    classifier: Classifier | None = None
    extractors: Mapping[str, Extractor] = field(default_factory=dict)
    skills: SkillRegistry = field(default_factory=SkillRegistry)
    render_template: str = ""
    observers: Sequence[Observer] = ()
    auth_allowlist: Mapping[str, Collection[str]] = field(default_factory=dict)

    def __post_init__(self) -> None:
        object.__setattr__(self, "name", validate_identifier(self.name.strip()))
        object.__setattr__(
            self,
            "extractors",
            {
                validate_identifier(name.strip()): extractor
                for name, extractor in self.extractors.items()
            },
        )
        object.__setattr__(self, "observers", tuple(self.observers))
        object.__setattr__(self, "auth_allowlist", self._normalized_allowlist())

    def allows(self, org: str, property_id: str) -> bool:
        org_id = validate_identifier(org.strip())
        allowed = self.auth_allowlist.get(org_id, frozenset())
        return validate_identifier(property_id.strip()) in allowed

    def _normalized_allowlist(self) -> dict[str, frozenset[str]]:
        return {
            validate_identifier(org.strip()): frozenset(
                validate_identifier(property_id.strip()) for property_id in properties
            )
            for org, properties in self.auth_allowlist.items()
        }

from __future__ import annotations

ORG_PROPERTIES: dict[str, frozenset[str]] = {
    "org_demo_berlin": frozenset({"LIE-001"}),
    "org_demo_hamburg": frozenset(),
}


def properties_for_org(org_id: str | None) -> frozenset[str]:
    if org_id is None:
        return frozenset()
    return ORG_PROPERTIES.get(org_id, frozenset())


def org_can_access(org_id: str | None, property_id: str) -> bool:
    return property_id in properties_for_org(org_id)

