from __future__ import annotations

import csv
import io
from collections.abc import Iterable
from datetime import UTC, date, datetime
from decimal import Decimal, InvalidOperation
from typing import Literal
from xml.etree.ElementTree import Element, fromstring

from pydantic import AwareDatetime, BaseModel, ConfigDict, JsonValue

from app.extract.models import (
    ExtractionResult,
    Fact,
    FactStatus,
    GapSignal,
    Payload,
    SourceCitation,
)
from app.ingest.envelope import Envelope, Identifier, UriString

CSV_SKILL_NAME = "parse-bank-csv"
CAMT_SKILL_NAME = "parse-camt053"
SOURCE_KIND_CSV: Identifier = "bank-csv"
SOURCE_KIND_CAMT: Identifier = "camt053"
CAMT_NAMESPACE = "{urn:iso:std:iso:20022:tech:xsd:camt.053.001.02}"

Direction = Literal["credit", "debit"]


class BankCsvInput(BaseModel):
    model_config = ConfigDict(extra="forbid", frozen=True)

    payload: str
    property_id: Identifier
    source_id: Identifier
    source_uri: UriString | None = None
    source_timestamp: AwareDatetime | None = None
    delimiter: str = ";"


class CamtInput(BaseModel):
    model_config = ConfigDict(extra="forbid", frozen=True)

    payload: str
    property_id: Identifier
    source_id: Identifier
    source_uri: UriString | None = None
    source_timestamp: AwareDatetime | None = None


async def parse_bank_csv(skill_input: BankCsvInput) -> ExtractionResult:
    reader = csv.DictReader(
        io.StringIO(skill_input.payload),
        delimiter=skill_input.delimiter,
    )
    facts: list[Fact] = []
    gap_signals: list[GapSignal] = []
    for index, row in enumerate(reader):
        reference = _csv_reference(row)
        if reference is None:
            gap_signals.append(
                _gap(
                    skill_input.property_id,
                    skill_input.source_id,
                    f"row {index} missing Kundenreferenz (End-to-End)",
                    "missing",
                )
