from __future__ import annotations

import json
from collections.abc import Mapping
from typing import Protocol, runtime_checkable


@runtime_checkable
class LLMClient(Protocol):
    async def complete(
        self,
        *,
        system_prompt: str,
        user_prompt: str,
        model: str | None = None,
    ) -> str:
        """Return raw model text for a single non-streaming prompt."""


class StaticLLMClient:
    """Deterministic LLM substitute that returns canned responses keyed by user prompt."""

    def __init__(self, responses: Mapping[str, str] | None = None, default: str = "") -> None:
        self._responses = dict(responses or {})
        self._default = default

    def queue(self, key: str, response: str) -> None:
        self._responses[key] = response

    async def complete(
        self,
        *,
        system_prompt: str,
        user_prompt: str,
        model: str | None = None,
    ) -> str:
        return self._responses.get(user_prompt, self._default)


def parse_json_response(text: str) -> object:
    cleaned = text.strip()
    if cleaned.startswith("```"):
        first_newline = cleaned.find("\n")
        if first_newline != -1:
            cleaned = cleaned[first_newline + 1 :]
        if cleaned.endswith("```"):
            cleaned = cleaned[:-3]
    return json.loads(cleaned)

