from collections.abc import Collection, Mapping, Sequence
from dataclasses import dataclass, field
from typing import Protocol, runtime_checkable

from pydantic import BaseModel, ConfigDict, Field, JsonValue

from app.extract.models import Extractor, Payload
from app.ingest.envelope import Envelope, validate_identifier
from app.skills.base import SkillRegistry


class ObservedEvent(BaseModel):
    model_config = ConfigDict(extra="forbid", frozen=True)

    kind: str
    payload: dict[str, JsonValue] = Field(default_factory=dict)
    idempotency_key: str | None = None


@runtime_checkable
class Classifier(Protocol):
    async def classify(self, envelope: Envelope, payload: Payload) -> str:
        """Classify one envelope before extractor routing."""


@runtime_checkable
class Observer(Protocol):
    async def observe(self, event: str, payload: BaseModel) -> Sequence[ObservedEvent]:
        """Observe engine events; return zero or more events the engine should log."""


@dataclass(frozen=True)
class VerticalPlugin:
    name: str
    classifier: Classifier | None = None
    extractors: Mapping[str, Extractor] = field(default_factory=dict)
    skills: SkillRegistry = field(default_factory=SkillRegistry)
    render_template: str = ""
    observers: Sequence[Observer] = ()
    auth_allowlist: Mapping[str, Collection[str]] = field(default_factory=dict)

    def __post_init__(self) -> None:
        object.__setattr__(self, "name", validate_identifier(self.name.strip()))
        object.__setattr__(
            self,
            "extractors",
            {
                validate_identifier(name.strip()): extractor
                for name, extractor in self.extractors.items()
            },
        )
        object.__setattr__(self, "observers", tuple(self.observers))
        object.__setattr__(self, "auth_allowlist", self._normalized_allowlist())

    def allows(self, org: str, property_id: str) -> bool:
        org_id = validate_identifier(org.strip())
        allowed = self.auth_allowlist.get(org_id, frozenset())
        return validate_identifier(property_id.strip()) in allowed

    def _normalized_allowlist(self) -> dict[str, frozenset[str]]:
        return {
            validate_identifier(org.strip()): frozenset(
                validate_identifier(property_id.strip()) for property_id in properties
            )
            for org, properties in self.auth_allowlist.items()
        }


_ACTIVE: dict[str, VerticalPlugin] = {}


def install_active_plugin(plugin: VerticalPlugin) -> None:
    _ACTIVE["plugin"] = plugin


def get_active_plugin() -> VerticalPlugin:
    plugin = _ACTIVE.get("plugin")
    if plugin is None:
        msg = "active vertical plugin is not installed"
        raise RuntimeError(msg)
    return plugin


def clear_active_plugin() -> None:
    _ACTIVE.pop("plugin", None)

