from __future__ import annotations

from collections.abc import Iterable, Mapping
from datetime import UTC, datetime
from typing import Annotated

from anyio.to_thread import run_sync
from fastapi import APIRouter, Depends, HTTPException, Path, Query, status
from fastapi.responses import PlainTextResponse

from app.api.v1.access import assert_property_access, current_org_id
from app.core.config import Settings, get_settings
from app.ingest.envelope import IDENTIFIER_PATTERN
from app.render import building_markdown_path, collect_render_records, render_building_markdown
from app.schemas.properties import (
    CiteResponse,
    FactCitation,
    FactList,
    FactRead,
    PendingList,
    PendingQuestion,
)
from app.storage.facts import FactsStore, open_facts

router = APIRouter()

PropertyIdPath = Annotated[
    str,
    Path(min_length=1, max_length=128, pattern=IDENTIFIER_PATTERN),
]
FactIdPath = Annotated[
    str,
    Path(min_length=1, max_length=128, pattern=IDENTIFIER_PATTERN),
]


def _open(settings: Settings) -> FactsStore:
    return open_facts(settings.output_dir / "facts.duckdb")


def _aware(value: object) -> datetime:
    if isinstance(value, datetime):
        return value if value.tzinfo else value.replace(tzinfo=UTC)
    raise TypeError(f"expected datetime, got {type(value).__name__}")


def _to_citation(row: Mapping[str, object]) -> FactCitation:
    return FactCitation(
        source_id=_opt_str(row.get("source_id")),
        source_kind=_opt_str(row.get("source_kind")),
        source_uri=None,
        locator=_opt_str(row.get("source_locator")),
        quote=_opt_str(row.get("source_excerpt")),
        payload_hash=_opt_str(row.get("content_hash")),
        source_timestamp=_opt_dt(row.get("source_timestamp")),
    )


def _opt_str(value: object) -> str | None:
    if value is None:
        return None
    return str(value)


def _opt_dt(value: object) -> datetime | None:
    if value is None:
        return None
    return _aware(value)


def _to_fact_read(row: Mapping[str, object]) -> FactRead:
    return FactRead(
        fact_id=str(row["fact_id"]),
        property_id=str(row["property_id"]),
        section=str(row["section"]),
        key=str(row["key"]),
        value=row["value"],  # type: ignore[arg-type]
        status=str(row["status"]),
        confidence=float(row["confidence"]),  # type: ignore[arg-type]
        asserted_at=_aware(row["asserted_at"]),
        citation=_to_citation(row),
    )


def _emit_query_miss(
    store: FactsStore,
    *,
    org_id: str,
    property_id: str,
    surface: str,
    detail: str,
) -> None:
    store.append_event(
        "query_miss",
        {
            "org_id": org_id,
            "property_id": property_id,
            "surface": surface,
            "detail": detail,
        },
    )


@router.get("/{property_id}/active", response_model=FactList)
async def list_active(
    property_id: PropertyIdPath,
    org_id: Annotated[str, Depends(current_org_id)],
    settings: Annotated[Settings, Depends(get_settings)],
    section: Annotated[str | None, Query(max_length=128, pattern=IDENTIFIER_PATTERN)] = None,
) -> FactList:
    assert_property_access(org_id, property_id)

    def fetch() -> list[dict[str, object]]:
        store = _open(settings)
        if section is not None:
            rows = store.list_active_facts_by_section(property_id, section)
        else:
            rows = store.list_active_facts(property_id)
        if not rows:
            _emit_query_miss(
                store,
                org_id=org_id,
                property_id=property_id,
                surface=f"http:active:{section or '*'}",
                detail="no active facts",
            )
        return rows

    rows = await run_sync(fetch)
    return FactList(property_id=property_id, facts=[_to_fact_read(row) for row in rows])


@router.get("/{property_id}/pending", response_model=PendingList)
async def list_pending(
    property_id: PropertyIdPath,
    org_id: Annotated[str, Depends(current_org_id)],
    settings: Annotated[Settings, Depends(get_settings)],
) -> PendingList:
    assert_property_access(org_id, property_id)

    def fetch() -> list[dict[str, object]]:
        store = _open(settings)
        rows = [
            row
            for row in store.list_facts()
            if str(row["property_id"]) == property_id and row["status"] == "pending"
        ]
        if not rows:
            _emit_query_miss(
                store,
                org_id=org_id,
                property_id=property_id,
                surface="http:pending",
                detail="no pending facts",
            )
        return rows

    rows = await run_sync(fetch)
    questions = [
        PendingQuestion(
            fact_id=str(row["fact_id"]),
            section=str(row["section"]),
            key=str(row["key"]),
            value=row["value"],  # type: ignore[arg-type]
            confidence=float(row["confidence"]),  # type: ignore[arg-type]
        )
        for row in rows
    ]
    return PendingList(property_id=property_id, questions=questions)


@router.get("/{property_id}/obligations", response_model=FactList)
async def list_obligations(
    property_id: PropertyIdPath,
    org_id: Annotated[str, Depends(current_org_id)],
    settings: Annotated[Settings, Depends(get_settings)],
) -> FactList:
    assert_property_access(org_id, property_id)

    def fetch() -> list[dict[str, object]]:
        store = _open(settings)
        rows = store.list_active_facts_by_section(property_id, "obligations")
        if not rows:
            _emit_query_miss(
                store,
                org_id=org_id,
                property_id=property_id,
                surface="http:obligations",
                detail="no obligations",
            )
        return rows

    rows = await run_sync(fetch)
    return FactList(property_id=property_id, facts=[_to_fact_read(row) for row in rows])


@router.get("/{property_id}/as_of", response_model=FactList)
async def list_as_of(
    property_id: PropertyIdPath,
    org_id: Annotated[str, Depends(current_org_id)],
    settings: Annotated[Settings, Depends(get_settings)],
    at: Annotated[datetime, Query(description="ISO8601 transaction-time")],
) -> FactList:
    assert_property_access(org_id, property_id)
    if at.tzinfo is None:
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST,
            detail="`at` must be timezone-aware",
        )

    def fetch() -> list[dict[str, object]]:
        store = _open(settings)
        return store.list_active_facts_as_of(at, property_id=property_id)

    rows = await run_sync(fetch)
    return FactList(property_id=property_id, facts=[_to_fact_read(row) for row in rows])


@router.get("/{property_id}/building.md", response_class=PlainTextResponse)
async def building_markdown(
    property_id: PropertyIdPath,
    org_id: Annotated[str, Depends(current_org_id)],
    settings: Annotated[Settings, Depends(get_settings)],
) -> PlainTextResponse:
    assert_property_access(org_id, property_id)

    def fetch() -> str:
        store = _open(settings)
        records = collect_render_records(store, property_id)
        return render_building_markdown(property_id, records)

    body = await run_sync(fetch)
    return PlainTextResponse(content=body, media_type="text/markdown")


@router.get("/-/facts/{fact_id}/cite", response_model=CiteResponse)
async def cite_fact(
    fact_id: FactIdPath,
    org_id: Annotated[str, Depends(current_org_id)],
    settings: Annotated[Settings, Depends(get_settings)],
) -> CiteResponse:
    def fetch() -> dict[str, object] | None:
        store = _open(settings)
        return store.fetch_fact(fact_id)

    row = await run_sync(fetch)
    if row is None:
        raise HTTPException(status_code=status.HTTP_404_NOT_FOUND, detail="fact not found")
    assert_property_access(org_id, str(row["property_id"]))
    return CiteResponse(fact_id=str(row["fact_id"]), citation=_to_citation(row))


__all__: Iterable[str] = ("router",)

