        key=str(row["key"]),
        value=row["value"],  # type: ignore[arg-type]
        status=str(row["status"]),
        confidence=float(row["confidence"]),  # type: ignore[arg-type]
        asserted_at=_aware(row["asserted_at"]),
        citation=_to_citation(row),
    )


