from __future__ import annotations

from collections.abc import Iterable
from datetime import UTC, datetime
from typing import Any

from anyio.to_thread import run_sync
from fastmcp import FastMCP
from fastmcp.exceptions import ResourceError, ToolError

from app.core.config import Settings
from app.extract.models import Fact, FactStatus, SourceCitation
from app.ingest.envelope import utc_now, validate_identifier
from app.mcp.access import assert_org_access
from app.mcp.orgs import properties_for_org
from app.render import collect_render_records, render_building_markdown
from app.storage.facts import FactsStore, open_facts


def _open(settings: Settings) -> FactsStore:
    return open_facts(settings.output_dir / "facts.duckdb")


def _aware(value: object) -> str | None:
    if value is None:
        return None
    if isinstance(value, datetime):
        dt = value if value.tzinfo else value.replace(tzinfo=UTC)
        return dt.isoformat()
    return str(value)


def _row_to_fact_dict(row: dict[str, Any]) -> dict[str, Any]:
    return {
        "fact_id": str(row["fact_id"]),
        "property_id": str(row["property_id"]),
        "section": str(row["section"]),
        "key": str(row["key"]),
        "value": row["value"],
        "status": str(row["status"]),
        "confidence": float(row["confidence"]),
        "asserted_at": _aware(row["asserted_at"]),
        "citation": _row_to_citation(row),
    }


def _row_to_citation(row: dict[str, Any]) -> dict[str, Any]:
    return {
        "source_id": _opt_str(row.get("source_id")),
        "source_kind": _opt_str(row.get("source_kind")),
        "locator": _opt_str(row.get("source_locator")),
        "quote": _opt_str(row.get("source_excerpt")),
        "payload_hash": _opt_str(row.get("content_hash")),
        "source_timestamp": _aware(row.get("source_timestamp")),
    }


def _opt_str(value: object) -> str | None:
    return None if value is None else str(value)


def _emit_query_miss(
    store: FactsStore,
    *,
    org_id: str,
    property_id: str,
    surface: str,
    detail: str,
) -> None:
    store.append_event(
        "query_miss",
        {
            "org_id": org_id,
            "property_id": property_id,
            "surface": surface,
            "detail": detail,
        },
    )


def build_mcp(settings: Settings) -> FastMCP:
    mcp: FastMCP = FastMCP(name="propcontext")

    def _check(org_id: str, property_id: str) -> str:
        try:
            return assert_org_access(org_id, property_id)
        except PermissionError as exc:
            raise ToolError(str(exc)) from exc
        except ValueError as exc:
            raise ToolError(str(exc)) from exc

    @mcp.tool(
        name="get_active_facts",
        description="Active facts for a property; optional section filter.",
    )
    async def get_active_facts(
        org_id: str,
        property_id: str,
        section: str | None = None,
    ) -> dict[str, Any]:
        pid = _check(org_id, property_id)

        def fetch() -> list[dict[str, Any]]:
            store = _open(settings)
            rows = (
                store.list_active_facts_by_section(pid, section)
                if section
                else store.list_active_facts(pid)
            )
            if not rows:
                _emit_query_miss(
                    store,
                    org_id=org_id,
                    property_id=pid,
                    surface=f"mcp:get_active_facts:{section or '*'}",
                    detail="no active facts",
                )
            return rows

        rows = await run_sync(fetch)
        return {"property_id": pid, "facts": [_row_to_fact_dict(row) for row in rows]}

    @mcp.tool(
        name="get_pending_questions",
        description="Pending facts (unresolved questions) for a property.",
    )
    async def get_pending_questions(org_id: str, property_id: str) -> dict[str, Any]:
        pid = _check(org_id, property_id)

        def fetch() -> list[dict[str, Any]]:
            store = _open(settings)
            rows = [
                row
                for row in store.list_facts()
                if str(row["property_id"]) == pid and row["status"] == "pending"
            ]
            if not rows:
                _emit_query_miss(
                    store,
                    org_id=org_id,
                    property_id=pid,
                    surface="mcp:get_pending_questions",
                    detail="no pending facts",
                )
            return rows

        rows = await run_sync(fetch)
        return {"property_id": pid, "questions": [_row_to_fact_dict(row) for row in rows]}

    @mcp.tool(
        name="get_obligations",
        description="Active facts in section 'obligations'.",
    )
    async def get_obligations(org_id: str, property_id: str) -> dict[str, Any]:
        pid = _check(org_id, property_id)

        def fetch() -> list[dict[str, Any]]:
            store = _open(settings)
            rows = store.list_active_facts_by_section(pid, "obligations")
            if not rows:
                _emit_query_miss(
                    store,
                    org_id=org_id,
                    property_id=pid,
                    surface="mcp:get_obligations",
                    detail="no obligations",
                )
            return rows

        rows = await run_sync(fetch)
        return {"property_id": pid, "facts": [_row_to_fact_dict(row) for row in rows]}

    @mcp.tool(
        name="time_travel",
        description="Active facts as of a transaction-time ISO8601 timestamp.",
    )
    async def time_travel(
        org_id: str,
        property_id: str,
        at: str,
    ) -> dict[str, Any]:
        pid = _check(org_id, property_id)
        try:
            moment = datetime.fromisoformat(at)
        except ValueError as exc:
            raise ToolError(f"invalid `at`: {exc}") from exc
        if moment.tzinfo is None:
            raise ToolError("`at` must be timezone-aware")

        def fetch() -> list[dict[str, Any]]:
            store = _open(settings)
            return store.list_active_facts_as_of(moment, property_id=pid)

        rows = await run_sync(fetch)
        return {
            "property_id": pid,
            "as_of": moment.isoformat(),
            "facts": [_row_to_fact_dict(row) for row in rows],
        }

    @mcp.tool(
        name="add_owner_note",
        description="Append an owner-authored note as an active fact.",
    )
    async def add_owner_note(
        org_id: str,
        property_id: str,
        section: str,
        key: str,
        note: str,
    ) -> dict[str, Any]:
        pid = _check(org_id, property_id)
        section_id = validate_identifier(section.strip())
        key_id = validate_identifier(key.strip())
        text = note.strip()
        if not text:
            raise ToolError("note must not be empty")

        now = utc_now()
        fact = Fact(
            property_id=pid,
            section=section_id,
            key=key_id,
            value={"note": text},
            citation=SourceCitation(
                source_id="owner",
                source_kind="owner_note",
                locator=f"owner:{org_id}",
            ),
            confidence=1.0,
            status=FactStatus.ACTIVE,
            asserted_at=now,
        )

        def commit() -> str:
            store = _open(settings)
            return store.upsert_fact(
                fact_id=fact.fact_id,
                property_id=fact.property_id,
                section=fact.section,
                key=fact.key,
                value=fact.value,
                status=fact.status.value,
                supersedes_fact_id=fact.supersedes_fact_id,
                asserted_at=fact.asserted_at,
                valid_from=fact.valid_interval.start,
                valid_to=fact.valid_interval.end,
                source_id=fact.citation.source_id,
                source_kind=fact.citation.source_kind,
                source_locator=fact.citation.locator,
                source_excerpt=fact.citation.quote,
                source_timestamp=fact.citation.source_timestamp,
                content_hash=fact.citation.payload_hash,
                extractor="mcp.owner_note",
                confidence=fact.confidence,
                idempotency_key=f"owner_note:{org_id}:{pid}:{section_id}:{key_id}:{now.isoformat()}",
            )

        fact_id = await run_sync(commit)
        return {"fact_id": fact_id, "property_id": pid, "section": section_id, "key": key_id}

    @mcp.tool(
        name="cite",
        description="Citation (source URI/locator/quote) for a single fact.",
    )
    async def cite(org_id: str, fact_id: str) -> dict[str, Any]:
        fid = validate_identifier(fact_id.strip())

        def fetch() -> dict[str, Any] | None:
            store = _open(settings)
            return store.fetch_fact(fid)

        row = await run_sync(fetch)
        if row is None:
            raise ToolError(f"fact {fid!r} not found")
        _check(org_id, str(row["property_id"]))
        return {"fact_id": fid, "citation": _row_to_citation(row)}

    @mcp.resource("property://{property_id}")
    async def property_resource(property_id: str) -> dict[str, Any]:
        pid = validate_identifier(property_id.strip())

        def fetch() -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
            store = _open(settings)
            active = store.list_active_facts(pid)
            pending = [
                row
                for row in store.list_facts()
                if str(row["property_id"]) == pid and row["status"] == "pending"
            ]
            return active, pending

        try:
            active, pending = await run_sync(fetch)
        except Exception as exc:
            raise ResourceError(f"failed to read property {pid!r}: {exc}") from exc

        return {
            "property_id": pid,
            "active_count": len(active),
            "pending_count": len(pending),
        }

    @mcp.resource("building://{org_id}/{property_id}/active")
    async def building_active(org_id: str, property_id: str) -> str:
        try:
            pid = assert_org_access(org_id, property_id)
        except (PermissionError, ValueError) as exc:
            raise ResourceError(str(exc)) from exc

        def fetch() -> str:
            store = _open(settings)
            records = [r for r in collect_render_records(store, pid) if r.get("status") == "active"]
            return render_building_markdown(pid, records)

        return await run_sync(fetch)

    @mcp.resource("building://{org_id}/{property_id}/pending")
    async def building_pending(org_id: str, property_id: str) -> str:
        try:
            pid = assert_org_access(org_id, property_id)
        except (PermissionError, ValueError) as exc:
            raise ResourceError(str(exc)) from exc

        def fetch() -> str:
            store = _open(settings)
            records = [
                r for r in collect_render_records(store, pid) if r.get("status") == "pending"
            ]
            return render_building_markdown(pid, records)

        return await run_sync(fetch)

    return mcp


