from __future__ import annotations

from collections.abc import Mapping, Sequence

from pydantic import BaseModel

from app.extract.models import Fact
from app.plugin import ObservedEvent, Observer

KNOWN_SECTIONS: frozenset[str] = frozenset(
    {
        "property",
        "contacts",
        "finance",
        "bank",
        "buildings",
        "units",
        "contracts",
        "obligations",
        "ingest",
    }
)

LEGAL_REQUIREMENTS: Mapping[str, frozenset[str]] = {
    "obligations": frozenset({"deadline", "responsible"}),
    "contracts": frozenset({"counterparty", "term"}),
}


class KnownSectionsObserver:
    async def observe(
        self,
        event: str,
        payload: BaseModel,
    ) -> Sequence[ObservedEvent]:
        if event != "fact.extracted" or not isinstance(payload, Fact):
            return ()
        if payload.section in KNOWN_SECTIONS:
            return ()
        return (
            ObservedEvent(
                kind="vocab_gap",
                payload={
                    "property_id": payload.property_id,
                    "section": payload.section,
                    "key": payload.key,
                    "reason": "section is not in property-de known vocabulary",
                },
                idempotency_key=f"vocab:{payload.property_id}:{payload.section}",
            ),
        )


class LegalMapObserver:
    async def observe(
        self,
        event: str,
        payload: BaseModel,
    ) -> Sequence[ObservedEvent]:
        if event != "fact.extracted" or not isinstance(payload, Fact):
            return ()
        required = LEGAL_REQUIREMENTS.get(payload.section)
        if required is None:
            return ()
        value = payload.value if isinstance(payload.value, dict) else {}
        missing = sorted(field for field in required if not value.get(field))
        if not missing:
            return ()
        return (
            ObservedEvent(
                kind="legal_gap",
                payload={
                    "property_id": payload.property_id,
                    "section": payload.section,
                    "key": payload.key,
                    "missing": missing,
                    "reason": "legal-map required fields not present in fact value",
                },
                idempotency_key=(f"legal:{payload.property_id}:{payload.section}:{payload.key}"),
            ),
        )


def build_observers() -> Sequence[Observer]:
    return (KnownSectionsObserver(), LegalMapObserver())

